import{_ as n,r,o,c as a,a as e,b as s,d as i,e as c}from"./app-76996780.js";const l="/MLblogs/assets/2024-03-18-09-42-42-image-7e96e978.png",p="/MLblogs/assets/2024-03-18-09-55-58-image-49b1859f.png",d={},h={class:"custom-container info"},m=e("svg",{xmlns:"http://www.w3.org/2000/svg","xmlns:xlink":"http://www.w3.org/1999/xlink",viewBox:"0 0 24 24"},[e("g",{fill:"none",stroke:"currentColor","stroke-width":"2","stroke-linecap":"round","stroke-linejoin":"round"},[e("circle",{cx:"12",cy:"12",r:"9"}),e("path",{d:"M12 8h.01"}),e("path",{d:"M11 12h1v4h1"})])],-1),g=e("p",{class:"custom-container-title"},"INFO",-1),_={href:"https://www.bilibili.com/video/BV1Ey4y1874y/?p=2&spm_id_from=333.1007.top_right_bar_window_history.content.click&vd_source=29624dbb703a504c9a36c90ccf9558d4",target:"_blank",rel:"noopener noreferrer"},f=c('<h2 id="网络结构和输入" tabindex="-1"><a class="header-anchor" href="#网络结构和输入" aria-hidden="true">#</a> 网络结构和输入</h2><p>BERT使用多个transformer的encoder堆叠而成，其输入有三个部分：token embeddings：比如随机初始化或者word2vec, Segment Embedding：表明这个词属于哪个句子（NSP需要两个句子）, position embeddings（可学习的）。</p><img src="'+l+'" title="" alt="" data-align="center"><h2 id="如何预训练-mlm-nsp" tabindex="-1"><a class="header-anchor" href="#如何预训练-mlm-nsp" aria-hidden="true">#</a> 如何预训练：MLM+NSP</h2><p><strong>MLM：掩码语言模型</strong></p><p>即完形填空问题。将部分词mask掉，然后传入BERT，最后在MASK掉的词的位置接一个Sofmax层用于输出该位置的应该填的词的概率。</p><p><strong>缺点:</strong> 若同时mask相邻的单词，如：P(我爱吃饭|我爱maskmask)=P(吃|我爱)P(饭|我爱)这里将&#39;吃&#39;和&#39;饭&#39;独立出来了，但是这两个词是很可能有关系的。</p><p><strong>mask概率问题：</strong></p><p>随机mask 15% 的单词，这些mask掉的单词中，10%替换成其他，10%原封不动，80%替换成mask。下面代码的mask_indices指的是那15%需要处理的单词。</p><img src="'+p+'" title="" alt="" data-align="center"><p><strong>NSP: next sentence prediction</strong></p><p>为了能让模型学习到句子级别的语义信息，在模型的学习目标中添加了Next Sentence Prediction任务。其实就是<strong>预测两个句子是否是前后相邻的两个句子</strong>。</p><p>NSP的样本：从训练语料库中抽取两个连续的段落作为正样本；从不同文档中随机创建一对段落作为负样本。</p><p>缺点：将主题预测和连贯性预测合并为了一个单项任务。主题预测：判断两个句子是否来自同一个文档，连贯性预测：判断两个段落是不是顺序关系。主题预测非常容易学习。</p><h2 id="下游任务" tabindex="-1"><a class="header-anchor" href="#下游任务" aria-hidden="true">#</a> 下游任务</h2><p>文本相似度匹配：与单个句子的分类类似，只是把两个句子拼接成一个句子，句子之间加一个[SEP]的token。最后将[CLS]拿去分类。</p><p>单个句子分类：在句子前面加上[CLS]这个token，然后将句子输入Encoder，将[CLS]所在位置的hidden output作为整句话的表征，输入Softmax层进行分类。</p><p>问答：将问题传入bert，bert生成文本</p><h2 id="如何微调bert" tabindex="-1"><a class="header-anchor" href="#如何微调bert" aria-hidden="true">#</a> 如何微调BERT</h2><p>微调的四个步骤：比如做微博文本情感分析</p><ol><li><p>使用预训练模型（pretrain）</p></li><li><p>在相同领域的数据集中继续训练（domain transfer, 在大量微博文本预训练）</p></li><li><p>在任务相关的小数据集中继续训练（task transfer, 微博情感文本，有的文本不属于情感文本范畴）</p></li><li><p>在任务相关数据上做具体任务（fine-tune）</p></li></ol><h2 id="相关面试题" tabindex="-1"><a class="header-anchor" href="#相关面试题" aria-hidden="true">#</a> 相关面试题</h2><p><strong>BERT的双向体现在哪？</strong></p><blockquote><p>双向性体现在其预训练过程和模型架构中：</p><p><strong>预训练任务</strong>：</p><ul><li>BERT 使用了两种不同的预训练任务来实现双向性：Masked Language Model（MLM）和Next Sentence Prediction（NSP）。</li><li>MLM 任务要求模型预测输入文本中部分单词被遮盖后的原始单词，这使得模型在预训练过程中需要考虑上下文中的所有单词信息，以便更好地填补被遮盖的单词。</li><li>NSP 任务要求模型判断两个句子是否是连续的，这鼓励模型学习句子之间的语义关系，包括句子的顺序、逻辑和连续性，使得模型能够理解句子之间的上下文关系。</li></ul><p><strong>模型架构</strong>：</p><ul><li>BERT 使用了 Transformer 编码器作为其基础模型架构。Transformer 模型由多个编码器层组成，每个编码器层都是一个由自注意力机制和前馈神经网络组成的模块。</li><li>在自注意力机制中，Transformer 模型能够同时考虑输入序列中每个位置的上下文信息，从而实现了双向的信息流动。这意味着在每个位置处，模型都可以利用序列中其他位置的信息来编码该位置的表示。</li></ul></blockquote>',24);function k(u,b){const t=r("ExternalLinkIcon");return o(),a("div",null,[e("div",h,[m,g,e("p",null,[e("a",_,[s("Bert输入部分详细解读_哔哩哔哩_bilibili"),i(t)])])]),f])}const S=n(d,[["render",k],["__file","BERT.html.vue"]]);export{S as default};
